const badgeId = "ENTRY-" + Date.now();  // Changed from "SHIFT-" to "ENTRY-"
const timestamp = new Date().toISOString();

// Get the original webhook data
const webhookData = $('Receive Visitor Registration').item.json.body;

return [{
  json: {
    ...webhookData,  // This preserves all visitor data
    badge_id: badgeId,
    timestamp: timestamp,
    email: $('Verify Visitor Email').item.json.email  // Add email back from verification
  }
}];

